namespace InventoryApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateOnly LastInspected);

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetEquipmentAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Forklift A", "Warehouse 1", new DateOnly(2026, 4, 10)),
            new(2, "Conveyor Belt B", "Warehouse 2", new DateOnly(2026, 3, 22)),
            new(3, "Crane C", "Yard", new DateOnly(2026, 5, 1)),
            new(4, "Pallet Jack D", "Warehouse 1", new DateOnly(2026, 2, 15)),
            new(5, "Compressor E", "Maintenance Bay", new DateOnly(2026, 1, 30)),
            new(6, "Welding Rig F", "Shop Floor", new DateOnly(2025, 12, 18)),
            new(7, "Drill Press G", "Shop Floor", new DateOnly(2026, 5, 12)),
            new(8, "Generator H", "Yard", new DateOnly(2026, 4, 28)),
        };
    }
}

@page "/inventory"
@using InventoryApp.Services
@inject IEquipmentService EquipmentService
@attribute [StreamRendering]

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToString("yyyy-MM-dd")</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? items;

    protected override async Task OnInitializedAsync()
    {
        items = await EquipmentService.GetEquipmentAsync();
    }
}

